// Pick ECP or fallback to the first key in the row
function getEcp(row) {
  if (row.ECP !== undefined) return row.ECP;
  const keys = Object.keys(row);
  return keys.length ? row[keys[0]] : '';
}
const out = [];
for (const i of items) {
  const raw = String(getEcp(i.json) ?? '').trim();
  if (!raw) continue;

  // Your device adds exactly 3 zeros in front of the real barcode
  // Remove up to the first 3 zeros only
  const barcode = raw.replace(/^0{1,3}/, '');

  // Skip empties after normalization
  if (!barcode) continue;

  out.push({ json: { ecp: raw, barcode } });
}
return out;

const seen = new Set();
const out = [];
for (const it of items) {
  const bc = it.json.barcode;
  if (bc && !seen.has(bc)) { seen.add(bc); out.push(it); }
}
return out;

// Input: many items, each { barcode }
// Output: one item { scannedBarcodes: [...] }
const barcodes = items
  .map(i => String(i.json.barcode ?? '').trim())
  .filter(Boolean);

return [{ json: { scannedBarcodes: [...new Set(barcodes)] } }];

