# Summary node - Python
# Input: output of Merge (Append from Pack scanned barcodes + Get CTL + Get MUON)
def norm_bc(v):
    if v is None:
        return None
    return str(v).strip()
def get_product_info(rec):
    """
    product_id in your data: [id, "NAME"]
    """
    val = rec.get("product_id")
    pid = None
    pname = None
    if val is not None:
        try:
            seq = list(val)
        except TypeError:
            seq = []
        if seq:
            pid = seq[0]
            if len(seq) > 1:
                pname = seq[1]
    if pname is None:
        pname = rec.get("name") or rec.get("product_name")
    return pid, pname
# 1) Split Merge input -> scanned, CTL, MUON
items = _input.all()
scanned_set = set()
ctl_records = []
muon_records = []
for it in items:
    j = it["json"]
    if "scannedBarcodes" in j:
        for bc in j.get("scannedBarcodes", []):
            bcn = norm_bc(bc)
            if bcn:
                scanned_set.add(bcn)
    elif j.get("display_name") == "CTL/Stock":
        ctl_records.append(j)
    elif j.get("display_name") == "MUON/Stock":
        muon_records.append(j)
total_scanned = len(scanned_set)
total_ctl = len(ctl_records)
total_muon = len(muon_records)
# 2) Index CTL + MUON
ctl_by_bc = {}
for rec in ctl_records:
    bc = norm_bc(rec.get("x_studio_barcode"))
    if bc:
        ctl_by_bc[bc] = rec
muon_barcodes = {
    norm_bc(rec.get("x_studio_barcode"))
    for rec in muon_records
    if norm_bc(rec.get("x_studio_barcode"))
}
# 3) Missing list
missing_items = []
for bc, rec in ctl_by_bc.items():
    if bc not in muon_barcodes and bc not in scanned_set:
        missing_items.append((bc, rec))
missing_count = len(missing_items)
# 4) Summary text (no full list, just a short preview)
summary_text = (
    "📦 Stock scan summary\n\n"
    f"• Total scanned barcodes (unique): {total_scanned}\n"
    f"• Total CTL/Stock items: {total_ctl}\n"
    f"• Total MUON/Stock items: {total_muon}\n"
    f"• Missing (in CTL, not in MUON, not scanned): {missing_count}\n"
)
messages = [summary_text]
# 5) Optional preview: first 20 missing names, *without* barcode
PREVIEW = 20
if missing_items:
    current = "Top missing items (product_id product_name):\n"
    for bc, rec in missing_items[:PREVIEW]:
        pid, pname = get_product_info(rec)
        pid_str = f"[{pid}]" if pid is not None else "[?]"
        name_str = pname or ""
        current += f"- {pid_str} {name_str}\n"
    current += f"\n(Full list attached as CSV)"
    messages.append(current)
# 6) Output for Telegram text node
return [{ "json": { "text": msg } } for msg in messages]
